// // This comment is misleading because it suggests the LED pattern is controlled by the least significant 8 bits of the counter, which is not the case.
module top_module( input clk50,
  output [7:0] LEDS
);reg [31:0] counter = 0;

	assign LEDS[7:0]=8'b11111111&counter[31:24];

	always @(posedge clk50)
	begin
		counter <= counter + 1'b1; 
	end

endmodule
